/*
 * Cloud Load Balancer Simulation
 * Demonstrates request distribution across virtual machines in a cloud environment
 * This is fundamental to understanding how cloud systems handle scalability
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_SERVERS 10
#define MAX_REQUESTS 100

// Server structure representing a compute node in the cloud
typedef struct {
    char server_id[20];
    int cpu_cores;
    int memory_mb;
    int current_load;      // Current number of active requests
    int max_capacity;      // Maximum requests it can handle
    int is_active;         // Whether server is running
} Server;

// Request structure
typedef struct {
    int request_id;
    int required_resources;
    char user_id[30];
} Request;

// Global server pool
Server server_pool[MAX_SERVERS];
int server_count = 0;

// Initialize a server in the pool
void add_server(char* id, int cpu, int memory, int capacity) {
    strcpy(server_pool[server_count].server_id, id);
    server_pool[server_count].cpu_cores = cpu;
    server_pool[server_count].memory_mb = memory;
    server_pool[server_count].max_capacity = capacity;
    server_pool[server_count].current_load = 0;
    server_pool[server_count].is_active = 1;
    server_count++;
    printf("Added server: %s (CPU: %d, Memory: %dMB, Capacity: %d requests)\n", 
           id, cpu, memory, capacity);
}

// Round Robin load balancing algorithm
Server* round_robin_select() {
    static int current_index = 0;
    int attempts = 0;

    while (attempts < server_count) {
        if (server_pool[current_index].is_active && 
            server_pool[current_index].current_load < server_pool[current_index].max_capacity) {
            return &server_pool[current_index];
        }
        current_index = (current_index + 1) % server_count;
        attempts++;
    }
    return NULL;  // No server available
}

// Least Connections load balancing algorithm
Server* least_connections_select() {
    Server* selected = NULL;
    int min_load = INT_MAX;

    for (int i = 0; i < server_count; i++) {
        if (server_pool[i].is_active && 
            server_pool[i].current_load < server_pool[i].max_capacity &&
            server_pool[i].current_load < min_load) {
            min_load = server_pool[i].current_load;
            selected = &server_pool[i];
        }
    }
    return selected;
}

// Process a request using specified load balancing strategy
void process_request(Request* req, char* strategy) {
    Server* selected = NULL;

    if (strcmp(strategy, "ROUND_ROBIN") == 0) {
        selected = round_robin_select();
    } else if (strcmp(strategy, "LEAST_CONNECTIONS") == 0) {
        selected = least_connections_select();
    }

    if (selected != NULL) {
        selected->current_load++;
        printf("Request #%d (User: %s) -> Server: %s | Load: %d/%d\n",
               req->request_id, req->user_id, selected->server_id,
               selected->current_load, selected->max_capacity);
    } else {
        printf("Request #%d REJECTED - No available servers!\n", req->request_id);
        // In real cloud, this would trigger auto-scaling
    }
}

// Simulate auto-scaling (add more servers when load is high)
void auto_scale() {
    printf("\n[AUTO-SCALING] Adding new server to handle increased load...\n");
    char new_id[20];
    sprintf(new_id, "server-%d", server_count + 1);
    add_server(new_id, 8, 16384, 100);  // Add powerful server
}

// Display server pool status
void display_status() {
    printf("\n=== Server Pool Status ===\n");
    int total_load = 0;
    for (int i = 0; i < server_count; i++) {
        printf("%s: Load %d/%d (%.1f%% used)\n", 
               server_pool[i].server_id,
               server_pool[i].current_load,
               server_pool[i].max_capacity,
               (float)server_pool[i].current_load / server_pool[i].max_capacity * 100);
        total_load += server_pool[i].current_load;
    }
    printf("Total Load: %d requests across %d servers\n", total_load, server_count);
}

int main() {
    printf("======================================\n");
    printf("CLOUD LOAD BALANCER SIMULATION\n");
    printf("======================================\n\n");

    // Initialize cloud server pool (like virtual machines in a cloud)
    printf("Initializing Cloud Server Pool...\n");
    add_server("vm-1", 4, 8192, 50);
    add_server("vm-2", 4, 8192, 50);
    add_server("vm-3", 8, 16384, 80);

    printf("\n--- Testing Round Robin Strategy ---\n");
    // Simulate incoming requests
    Request requests[] = {
        {1, 10, "user1@email.com"},
        {2, 15, "user2@email.com"},
        {3, 10, "user3@email.com"},
        {4, 20, "user4@email.com"},
        {5, 10, "user5@email.com"},
        {6, 15, "user6@email.com"}
    };

    int num_requests = sizeof(requests) / sizeof(requests[0]);

    for (int i = 0; i < num_requests; i++) {
        process_request(&requests[i], "ROUND_ROBIN");
    }

    display_status();

    // Reset loads for next test
    for (int i = 0; i < server_count; i++) {
        server_pool[i].current_load = 0;
    }

    printf("\n--- Testing Least Connections Strategy ---\n");
    for (int i = 0; i < num_requests; i++) {
        process_request(&requests[i], "LEAST_CONNECTIONS");
    }

    display_status();

    // Demonstrate auto-scaling
    printf("\n--- Demonstrating Auto-Scaling ---\n");
    // Fill up current servers
    for (int i = 0; i < 150; i++) {
        Request r = {i + 100, 10, "bulk-user"};
        Server* selected = least_connections_select();
        if (selected == NULL) {
            auto_scale();  // Trigger auto-scaling
            selected = least_connections_select();
        }
        if (selected != NULL) {
            selected->current_load++;
        }
    }
    display_status();

    printf("\n======================================\n");
    printf("This demonstrates key cloud computing concepts:\n");
    printf("- Resource pooling (server pool)\n");
    printf("- Rapid elasticity (auto-scaling)\n");
    printf("- Measured service (load monitoring)\n");
    printf("======================================\n");

    return 0;
}
